//! Full Parity Test Suite: wasm4pm vs pm4py
//!
//! Comprehensive validation that wasm4pm produces identical results to pm4py
//! across all supported algorithms.
//!
//! Reference outputs generated by: comprehensive_pm4py_reference.py

use pictl::models::{AttributeValue, EventLog};
use std::collections::{HashMap, HashSet};
use std::fs;

const FIXTURES_DIR: &str = "tests/fixtures";

fn load_event_log(name: &str) -> EventLog {
    let path = format!("{FIXTURES_DIR}/{name}");
    let json_str =
        fs::read_to_string(&path).unwrap_or_else(|e| panic!("Failed to load {}: {}", path, e));
    serde_json::from_str(&json_str)
        .unwrap_or_else(|e| panic!("Failed to parse event log JSON from {}: {}", path, e))
}

fn load_pm4py<T: serde::de::DeserializeOwned>(name: &str) -> T {
    let path = format!("{FIXTURES_DIR}/{name}");
    let json_str = fs::read_to_string(&path)
        .unwrap_or_else(|e| panic!("Failed to load pm4py output {}: {}", path, e));
    serde_json::from_str(&json_str)
        .unwrap_or_else(|e| panic!("Failed to parse pm4py output JSON from {}: {}", path, e))
}

// ── Canonical DFG Representation ───────────────────────────────────────────

#[derive(Debug, Clone, PartialEq, Eq)]
struct CanonicalEdge {
    from: String,
    to: String,
    frequency: usize,
}

#[derive(Debug, Clone, PartialEq, Eq)]
struct CanonicalActivityCount {
    activity: String,
    count: usize,
}

#[derive(Debug, Clone, PartialEq)]
struct CanonicalDFG {
    activities: Vec<String>,
    edges: Vec<CanonicalEdge>,
    start_activities: Vec<CanonicalActivityCount>,
    end_activities: Vec<CanonicalActivityCount>,
}

impl CanonicalDFG {
    fn sort(&mut self) {
        self.activities.sort();
        self.edges
            .sort_by(|a, b| a.from.cmp(&b.from).then_with(|| a.to.cmp(&b.to)));
        self.start_activities
            .sort_by(|a, b| a.activity.cmp(&b.activity));
        self.end_activities
            .sort_by(|a, b| a.activity.cmp(&b.activity));
    }
}

fn build_dfg(log: &EventLog, activity_key: &str) -> CanonicalDFG {
    let mut activities = HashSet::new();
    let mut edges = HashMap::new();
    let mut start = HashMap::new();
    let mut end = HashMap::new();

    for trace in &log.traces {
        if trace.events.is_empty() {
            continue;
        }

        if let Some(AttributeValue::String(first)) = trace.events[0].attributes.get(activity_key) {
            *start.entry(first.clone()).or_insert(0) += 1;
            activities.insert(first.clone());
        }

        if let Some(AttributeValue::String(last)) =
            trace.events.last().unwrap().attributes.get(activity_key)
        {
            *end.entry(last.clone()).or_insert(0) += 1;
            activities.insert(last.clone());
        }

        for i in 0..trace.events.len().saturating_sub(1) {
            if let (Some(AttributeValue::String(from)), Some(AttributeValue::String(to))) = (
                trace.events[i].attributes.get(activity_key),
                trace.events[i + 1].attributes.get(activity_key),
            ) {
                *edges.entry((from.clone(), to.clone())).or_insert(0) += 1;
                activities.insert(from.clone());
                activities.insert(to.clone());
            }
        }
    }

    CanonicalDFG {
        activities: activities.into_iter().collect(),
        edges: edges
            .into_iter()
            .map(|((from, to), freq)| CanonicalEdge {
                from,
                to,
                frequency: freq,
            })
            .collect(),
        start_activities: start
            .into_iter()
            .map(|(a, c)| CanonicalActivityCount {
                activity: a,
                count: c,
            })
            .collect(),
        end_activities: end
            .into_iter()
            .map(|(a, c)| CanonicalActivityCount {
                activity: a,
                count: c,
            })
            .collect(),
    }
}

// ── TEST 1: DFG Discovery ───────────────────────────────────────────────────

#[test]
fn test_dfg_discovery_full_parity() {
    let log = load_event_log("running-example.json");
    let wasm4pm_dfg = build_dfg(&log, "activity");
    let mut wasm4pm_dfg = wasm4pm_dfg;
    wasm4pm_dfg.sort();

    let pm4py_dfg: serde_json::Value = load_pm4py("pm4py_dfg.json");

    let pm4py_activities: Vec<String> = pm4py_dfg["activities"]
        .as_array()
        .unwrap()
        .iter()
        .map(|v| v.as_str().unwrap().to_string())
        .collect();

    let pm4py_edges: Vec<CanonicalEdge> = pm4py_dfg["edges"]
        .as_array()
        .unwrap()
        .iter()
        .map(|v| CanonicalEdge {
            from: v["from"].as_str().unwrap().to_string(),
            to: v["to"].as_str().unwrap().to_string(),
            frequency: v["frequency"].as_u64().unwrap() as usize,
        })
        .collect();

    let pm4py_start: Vec<CanonicalActivityCount> = pm4py_dfg["start_activities"]
        .as_array()
        .unwrap()
        .iter()
        .map(|v| CanonicalActivityCount {
            activity: v["activity"].as_str().unwrap().to_string(),
            count: v["count"].as_u64().unwrap() as usize,
        })
        .collect();

    let pm4py_end: Vec<CanonicalActivityCount> = pm4py_dfg["end_activities"]
        .as_array()
        .unwrap()
        .iter()
        .map(|v| CanonicalActivityCount {
            activity: v["activity"].as_str().unwrap().to_string(),
            count: v["count"].as_u64().unwrap() as usize,
        })
        .collect();

    println!("\n=== DFG Discovery Parity Test ===");
    println!(
        "Activities: wasm4pm={}, pm4py={}",
        wasm4pm_dfg.activities.len(),
        pm4py_activities.len()
    );
    println!(
        "Edges: wasm4pm={}, pm4py={}",
        wasm4pm_dfg.edges.len(),
        pm4py_edges.len()
    );
    println!(
        "Start activities: wasm4pm={}, pm4py={}",
        wasm4pm_dfg.start_activities.len(),
        pm4py_start.len()
    );
    println!(
        "End activities: wasm4pm={}, pm4py={}",
        wasm4pm_dfg.end_activities.len(),
        pm4py_end.len()
    );

    assert_eq!(
        wasm4pm_dfg.activities, pm4py_activities,
        "Activities mismatch"
    );
    assert_eq!(wasm4pm_dfg.edges, pm4py_edges, "Edges mismatch");
    assert_eq!(
        wasm4pm_dfg.start_activities, pm4py_start,
        "Start activities mismatch"
    );
    assert_eq!(
        wasm4pm_dfg.end_activities, pm4py_end,
        "End activities mismatch"
    );

    println!("✅ DFG Discovery: FULL PARITY");
}

