// ── TEST 15: Final Integration Test ───────────────────────────────────────

#[test]
fn test_final_integration() {
    println!("\n=== Final Integration Test ===");

    // Test the complete pipeline: parse → analyze → export
    use pictl::powl::analysis::complexity::measure;
    use pictl::powl::conversion::to_bpmn::to_bpmn_xml;
    use pictl::powl::footprints::apply;
    use pictl::powl_arena::PowlArena;
    use pictl::powl_parser::parse_powl_model_string;

    let powl_str = "X(A, PO=(nodes={B, C}, order={}))";
    let mut arena = PowlArena::new();
    let root = parse_powl_model_string(powl_str, &mut arena).unwrap();

    // 1. Parse and analyze
    let fp = apply(&arena, root);
    println!(
        "  Footprints: {} activities, {} sequence pairs",
        fp.activities.len(),
        fp.sequence.len()
    );

    let complexity = measure(&arena, root);
    println!(
        "  Complexity: cyclomatic={}, cfc={}",
        complexity.cyclomatic, complexity.cfc
    );

    // 2. Export to BPMN
    let bpmn = to_bpmn_xml(&arena, root);
    println!(
        "  BPMN output (first 200 chars): {}",
        &bpmn.chars().take(200).collect::<String>()
    );
    println!("  BPMN length: {} bytes", bpmn.len());
    assert!(bpmn.contains("<definitions"), "BPMN has definitions");
    assert!(bpmn.contains("<task"), "BPMN has task");
    assert!(bpmn.contains("exclusiveGateway"), "BPMN has XOR gateway");
    assert!(
        bpmn.contains("parallelGateway"),
        "BPMN has parallel gateway"
    );
    println!("  BPMN: valid XML");

    println!("\n✅ Integration Test: Complete pipeline functional");
}

